var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하핫, 오랜만입니다, 쌤.","JPN":"ははっ、久しぶりやね。先生。","ENG":"Haha, long time no see, Teach.","TWN":"哈哈，好久不見了，老師。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이야~ 이거 삐까번쩍하네예? 설마 절 위해가꼬 이래 준비한 기가요?","JPN":"いやぁ～めっちゃ豪華やな。まさかウチのために用意してくれたん？","ENG":"Wow! This place is all shiny. Don't tell me you set this up for me?","TWN":"哎呀～這個閃閃發光耶？難道是為了我準備的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"에헤헤, 쫌 감동인데예? 호감도 살~짝 올랐을지도?","JPN":"えへへ、ちょっと感動したわ。こんなんやと好感度がもっと上がってまうやんか〜！","ENG":"Ehehe, I'm kinda touched. Maybe my affection score for you just ticked up a bit?","TWN":"欸嘿嘿，很感動耶？好感度也許稍～微上升了？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"……머, 쌤을 향한 제 호감도는 이미 만땅이지만.","JPN":"……まあウチ、先生への好感度はもうマックスやけど！","ENG":"...Well, not that it matters. Because my affection for you is already maxed out.","TWN":"……雖然我對你的好感度已經滿點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하핫! 농담입니다! 농담!","JPN":"あははっ！　冗談や、冗談！","ENG":"Ahaha! Just kiddin', just kiddin'!","TWN":"啊哈哈！開玩笑的啦！只是玩笑！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"우리 사이에 머 그리 쑥스러워할 게 있겠습니까?","JPN":"ウチと先生の仲だし、照れるも何もないって。","ENG":"C'mon, between us, what's there to be shy about?","TWN":"我們之間有什麼好害臊的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라믄? 이번에는 또 무슨 아티팩트를 찾아드릴까예?","JPN":"で、今回探すアーティファクトは何なん？","ENG":"So then. What Artifact do you want me to dig up for you this time?","TWN":"那麼，這次又要找什麼人造神器呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"어떤 일이든 맡겨주이소! 지금 전 쌤의 마음을 훔칠 트레저★헌터로 다시 태아났다 아닙니까!","JPN":"何でもウチに任せてな！　ウチは先生の心を盗むトレジャー★ハンターに生まれ変わったんや！","ENG":"Whatever it is, leave it to me! I've been reborn as the Treasure★Hunter who'll steal your heart!","TWN":"不管是什麼都包在我身上！我現在不是以偷走你心的尋寶★獵人重生了嗎！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하~ 이게 이번 의뢰서인갑네예!","JPN":"ははーん、これが今回の依頼書やな？","ENG":"Aha! So this is the new request form, huh?","TWN":"啊哈～看來這是這次的委託書！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"어디 보자……","JPN":"どれどれ……","ENG":"Let's see here...","TWN":"讓我看看……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"쌤예, 이거 잘못주신 거 아닙니까? 의뢰서가 아니라, 종신 계약서인데예?","JPN":"先生、これ、なんか間違ってへん？　依頼書やなくて終身契約書みたいやねんけど？","ENG":"Teach, you didn't hand me the wrong paper, did you? This isn't a request form, it's a lifetime contract.","TWN":"老師，你是不是給錯了？這不是委託書，是終身契約耶？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아앗! 설마! 쌤……!!","JPN":"ああっ！　まさか、先生……！！","ENG":"Ah! Don't tell me! Teach...!!","TWN":"啊啊！難道！老師……！！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"쌤과 계약해서 <color=#ffd34c>마법 소녀</color>가 되라카는 기가예?","JPN":"先生と契約して<color=#ffd34c>魔法少女</color>になってほしいんか？","ENG":"You're asking me to make a contract and become a <color=#ffd34c>magical girl</color>?","TWN":"是要和老師簽約，成為<color=#ffd34c>魔法少女</color>嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭐, 아무렴 마음만큼은 소녀니까… 쌤의 부탁이라면 못할 것도……?","JPN":"まあ、心だけは乙女やし……先生の頼みならできないことなんて……！","ENG":"Well, I mean... I'm still young at heart, so if it's you askin'...","TWN":"總之因為內心是少女…如果是老師拜託，也沒什麼辦不到的……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"……풉!","JPN":"……ぷっ！","ENG":"...Pfft!","TWN":"……噗！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하하하하하핫! 쌤~! 못 본 사이에 완전 귀여워지셨네예~?","JPN":"あははははっ！　先生～！　しばらく見ない間に可愛くなりはりましたね～！","ENG":"Ahahahahaha! Teach, you've gotten downright adorable while I was gone, huh?","TWN":"啊哈哈哈哈哈哈哈！老師～！這段時間沒見，你變得超可愛耶～？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"쌤이랑 저 사이에서 계약은 뭔 놈의 계약입니까?","JPN":"先生とウチの仲に契約なんかいらへんって！","ENG":"What kinda contract is this between you and me, anyway?","TWN":"老師和我之間要簽什麼契約呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"제 마음 속 종신 계약은, 이미 그때 동아리실에서 맺었다 아닙니까!","JPN":"ウチの心の中じゃ、終身契約はあの時の部室で締結済みや！","ENG":"Didn't we already make the real lifetime contract back in the club room?","TWN":"我心裡的終身契約，那時候在社辦不就已經簽了嗎！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"제 장래 계획도 그때 다 말했잖습니까? 앞으로 자나깨나 선생님 곁에 있겠다고.","JPN":"将来の計画もあの時全部話したやないですか！　寝ても覚めても先生のそばにいるって。","ENG":"I told you my future plans back then, remember? That I'd stick by your side, day and night.","TWN":"我當時不是還把將來計畫都告訴你了嗎？說之後要時時刻刻待在老師身邊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그러니께… 무슨 시련이 온다 캐도, 저는 쌤이랑 쭉 함께입니다. 쭈우욱-!","JPN":"せやから……どんな試練が来ようとも、ウチはずっと先生と一緒にいます。ずーっと！","ENG":"So no matter what trials come our way, I'll always be with you. Always!","TWN":"所以…不管遇到什麼考驗，我都會和老師在一起，一直-！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그 마음은, 각자 자기 자리에서 쌤을 도와주고 있는 다른 아들도 똑같을끼라 생각합니다.","JPN":"その気持ちは、それぞれの場所で先生を手伝ってるみんなもきっと同じやと思います。","ENG":"And I reckon the other kids, each helpin' you in their own way, feel the same.","TWN":"其他在各自的位置上幫忙老師的人也是這樣想的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그리고 저는, 제일 가까운 데서 쌤 옆을 지켜드릴끼예.","JPN":"そんで、ウチは、先生のいちばん近いとこで先生を守るんや。","ENG":"But me, I'll be the one right here, guarding your side.","TWN":"然後，我會在最近的地方守護你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"크, 크흠……!","JPN":"ご、ゴホン……！","ENG":"A-ahem...!","TWN":"咳、咳哼……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그래도 오랜만인 김에, 계약 한 번 해볼까예?","JPN":"まあでも久しぶりやし、契約は交わしてみるわ。","ENG":"Still, since it's been a while, how about we make a new contract for old times' sake?","TWN":"不過既然過了很久，我們就來簽個約吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"대신 쌤, 소원 하나 들어주이소.","JPN":"その代わりに、1つだけお願いがあるんやけど。","ENG":"But in return, grant me one wish, Teach.","TWN":"但是老師，請你幫我實現一個願望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};